      ]);
      expect(spy.calls.argsFor(1)).toEqual([new Delta(), {}, 1]);
      expect(spy.calls.argsFor(2)).toEqual([
        new Delta()
          .insert('World', { bold: true })
          .insert({ image: 'octocat.png' }),
        { align: 'right' },
        2,
      ]);
      expect(spy.calls.argsFor(3)).toEqual([new Delta().insert('!'), {}, 3]);
    });

